settings.custom_liquid:
{% comment %}
  Anleitung:
  1. HTML-Struktur für die Lieferinfo.
  2. CSS-Stile für ein modernes Aussehen (unverändert).
  3. JavaScript-Logik zur dynamischen Berechnung und Anzeige des Lieferdatums
     basierend auf der Regel: Bestellung bis Montag 08:00 Uhr -> Lieferung Freitag.
{% endcomment %}

<style>
  .delivery-info-wrapper {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif, "Apple Color Emoji", "Segoe UI Emoji", "Segoe UI Symbol"; /* Moderne, gängige Schriftarten */
    background-color: #f8f9fa; /* Heller Hintergrund */
    border: 1px solid #dee2e6;   /* Dezenter Rand */
    border-radius: 8px;          /* Abgerundete Ecken */
    padding: 20px;               /* Innenabstand */
    margin-top: 20px;            /* Abstand nach oben */
    margin-bottom: 20px;         /* Abstand nach unten */
    max-width: 400px;            /* Maximale Breite, um es kompakt zu halten */
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.05); /* Leichter Schatten für Tiefe */
    transition: all 0.3s ease-in-out; /* Sanfte Übergänge für Hover-Effekte (optional) */
  }

  /* Optional: Kleiner Hover-Effekt */
  /*
  .delivery-info-wrapper:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 12px rgba(0, 0, 0, 0.08);
  }
  */

  .delivery-info-wrapper .title {
    font-size: 1em;      /* Basis-Schriftgröße für den Titel */
    color: #495057;          /* Etwas gedämpftere Farbe für den Titel */
    margin: 0 0 8px 0;       /* Abstand unter dem Titel */
    font-weight: 600;        /* Etwas fetter als normal */
  }

  .delivery-info-wrapper .date {
    font-size: 1.6em;     /* Größere Schrift für das Datum */
    font-weight: 700;        /* Fett für das Datum */
    color: #28a745;          /* Auffällige Farbe (z.B. Grün für Lieferung), anpassbar! */
    /* Alternativ eine dunkle, seriöse Farbe: color: #343a40; */
    margin: 0 0 10px 0;      /* Abstand unter dem Datum */
    line-height: 1.2;
  }

  .delivery-info-wrapper .validity {
    font-size: 0.85em;    /* Kleinere Schrift für den Gültigkeitszeitraum */
    color: #6c757d;          /* Hellere Farbe für weniger Betonung */
    margin: 0;
    font-style: italic;
  }
</style>

<div id="dynamic-delivery-info" class="delivery-info-wrapper">
    <p class="title">Voraussichtlicher Liefertermin:</p>
    <p class="date"><strong>Lade Liefertermin...</strong></p>
    <p class="validity"><small>Bestellfenster wird berechnet...</small></p>
</div>

<script>
document.addEventListener('DOMContentLoaded', function() {
    /**
     * Formatiert ein Datumsobjekt in einen String (DD.MM.YYYY oder DD.MM.YYYY HH:MM).
     * @param {Date} dateObj Das zu formatierende Datumsobjekt.
     * @param {boolean} includeTime Gibt an, ob die Uhrzeit einbezogen werden soll.
     * @returns {string} Der formatierte Datumsstring.
     */
    function formatDate(dateObj, includeTime = false) {
        const day = String(dateObj.getDate()).padStart(2, '0');
        const month = String(dateObj.getMonth() + 1).padStart(2, '0'); // Monate sind 0-indiziert (Januar=0)
        const year = dateObj.getFullYear();
        if (includeTime) {
            const hours = String(dateObj.getHours()).padStart(2, '0');
            const minutes = String(dateObj.getMinutes()).padStart(2, '0');
            return `${day}.${month}.${year} ${hours}:${minutes}`;
        }
        return `${day}.${month}.${year}`;
    }

    const now = new Date();
    // --- Für Testzwecke können Sie ein festes Datum setzen ---
    // const now = new Date(2025, 4, 12, 7, 0, 0);  // Mo, 12.05.2025, 07:00 -> Lieferung Fr, 16.05.2025
    // const now = new Date(2025, 4, 12, 8, 0, 0);  // Mo, 12.05.2025, 08:00 -> Lieferung Fr, 23.05.2025
    // const now = new Date(2025, 4, 12, 10, 0, 0); // Mo, 12.05.2025, 10:00 -> Lieferung Fr, 23.05.2025
    // const now = new Date(2025, 4, 14, 15, 0, 0); // Mi, 14.05.2025, 15:00 -> Lieferung Fr, 23.05.2025
    // const now = new Date(2025, 4, 18, 23, 0, 0); // So, 18.05.2025, 23:00 -> Lieferung Fr, 23.05.2025 (Cutoff Mo 19.05 08:00)

    let determinedDeliveryDateString = "Bitte kontaktieren Sie uns.";
    let determinedValidityString = "Für den nächsten möglichen Liefertermin.";

    // Berechne den Montag, 08:00 Uhr der aktuellen Woche
    let currentWeeksMonday8AM = new Date(now);
    // setDate passt den Monat/Jahr automatisch an, falls nötig
    // getDay(): So=0, Mo=1, Di=2, ..., Sa=6
    // (currentWeeksMonday8AM.getDay() + 6) % 7 ergibt: 0 für Mo, 1 für Di, ..., 6 für So
    // Ziel: Gehe zurück zum Montag dieser Woche
    currentWeeksMonday8AM.setDate(currentWeeksMonday8AM.getDate() - (currentWeeksMonday8AM.getDay() + 6) % 7);
    currentWeeksMonday8AM.setHours(8, 0, 0, 0); // Setze die Uhrzeit auf 08:00:00

    let actualCutoffDateTime; // Der genaue Zeitpunkt, an dem das Bestellfenster endet (z.B. Montag, 19.05.2025, 08:00:00)
    let validFromDateTime;    // Der Zeitpunkt, an dem das Bestellfenster beginnt (z.B. Montag, 12.05.2025, 08:00:00)

    if (now < currentWeeksMonday8AM) {
        // Die aktuelle Zeit liegt VOR Montag 08:00 Uhr dieser Woche
        // (z.B. es ist Sonntag oder Montag 07:00 Uhr)
        // Das Bestellfenster endet also an diesem Montag um 08:00 Uhr.
        actualCutoffDateTime = new Date(currentWeeksMonday8AM);
        // Das Bestellfenster begann am Montag der Vorwoche um 08:00 Uhr.
        validFromDateTime = new Date(currentWeeksMonday8AM);
        validFromDateTime.setDate(validFromDateTime.getDate() - 7);
    } else {
        // Die aktuelle Zeit liegt AN oder NACH Montag 08:00 Uhr dieser Woche
        // (z.B. es ist Montag 09:00 Uhr oder Dienstag)
        // Das Bestellfenster begann an diesem Montag um 08:00 Uhr.
        validFromDateTime = new Date(currentWeeksMonday8AM);
        // Das Bestellfenster endet am Montag der NÄCHSTEN Woche um 08:00 Uhr.
        actualCutoffDateTime = new Date(currentWeeksMonday8AM);
        actualCutoffDateTime.setDate(actualCutoffDateTime.getDate() + 7);
    }

    // Die Lieferung erfolgt am Freitag der Woche, in die actualCutoffDateTime fällt (welches ein Montag ist).
    let deliveryDate = new Date(actualCutoffDateTime);
    // Montag (Tag 1 in getDay(), wenn So=0) + 4 Tage = Freitag (Tag 5)
    deliveryDate.setDate(deliveryDate.getDate() + 4);

    // Formatierung für die Anzeige
    determinedDeliveryDateString = formatDate(deliveryDate); // Format: DD.MM.YYYY

    // Das Bestellfenster endet technisch gesehen eine Sekunde vor dem actualCutoffDateTime.
    let validToDisplayDateTime = new Date(actualCutoffDateTime);
    validToDisplayDateTime.setSeconds(validToDisplayDateTime.getSeconds() - 1); // z.B. Montag 07:59:59 Uhr

    const validFromStr = formatDate(validFromDateTime, true); // Format: DD.MM.YYYY HH:MM
    const validToStr = formatDate(validToDisplayDateTime, true);   // Format: DD.MM.YYYY HH:MM

    determinedValidityString = `(Bestellfenster: ${validFromStr} Uhr – ${validToStr} Uhr)`;

    // DOM-Elemente aktualisieren
    const deliveryInfoContainer = document.getElementById('dynamic-delivery-info');
    if (deliveryInfoContainer) {
        const deliveryDateElement = deliveryInfoContainer.querySelector('.date strong');
        const validityPeriodElement = deliveryInfoContainer.querySelector('.validity small');

        if (deliveryDateElement) {
            deliveryDateElement.textContent = determinedDeliveryDateString;
        }
        if (validityPeriodElement) {
            validityPeriodElement.textContent = determinedValidityString;
        }
    } else {
        console.error("Dynamische Lieferinfo: Container 'dynamic-delivery-info' nicht im DOM gefunden.");
    }
});
</script>
